import React from 'react'
import useCheckStore from '../../store/useCheckStore'
import { useTranslation } from 'react-i18next';
import CheckCircleIcon from '@mui/icons-material/CheckCircle';
import Paper from '@mui/material/Paper';
import { getShortName, styleIcon } from '../../util/func';
import { pickups } from '../../constant/updates';
import useTheme from '@mui/material/styles/useTheme';
import ImageListItem from '@mui/material/ImageListItem';
import ImageListItemBar from '@mui/material/ImageListItemBar';

// 캐릭터 체크 UI
const CharacterCheck: React.FC<CharacterInfo> = (info) => {

    const { addInven, removeInven, inven } = useCheckStore();
    const { t, i18n } = useTranslation()
    const theme = useTheme()

    const name = t(`c${info.code}`);
    const checked = inven.includes(info.id);

    const toggleInven = () => {
        const id = info.id;
        const from = info.from!;    // 체크하는 캐릭터는 반드시 존재
        if (checked)
            removeInven(id)
        else {
            addInven(id)
            for (const i of from) {
                addInven(i)
            }
        }
    }
    return (
        <Paper
            sx={{
                minWidth: 75,
                maxWidth: 75,
                cursor: "pointer",
                position: "relative",
            }}
            onClick={toggleInven}
        >
            {styleIcon(info)}
            <ImageListItem >
                <img
                    src={`/image/data/${info.id}.png`}
                    alt={name}
                    style={{
                        border: pickups.includes(info.id) ? `3px solid ${theme.palette.secondary.main}` : "",
                        borderRadius: "5px",
                        boxSizing: "border-box",
                        pointerEvents: "none",
                    }}
                />
                {checked ?
                    <CheckCircleIcon color="info" fontSize='large'
                        sx={{
                            position: "absolute",
                            right: -5,
                            top: -5,
                            zIndex: 1,
                            backgroundColor: theme.palette.background.paper,
                            borderRadius: "100px",
                        }}
                    />
                    : null}
                <ImageListItemBar subtitle={getShortName(name, i18n.language)} sx={{
                    height: 22,
                    "& .MuiImageListItemBar-subtitle": {
                        textAlign: "center",
                        fontSize: "12px",
                    },
                    ".MuiImageListItemBar-titleWrap": {
                        padding: 0.5
                    }
                }} />
            </ImageListItem>
        </Paper>
    )
}

export default CharacterCheck